const Q_GEOGRAPHY_2005=[{"id": "objective>Geography>2005>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The total area covered by the map is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">288sqkm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">278sq km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">258sq km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">268sq km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scale = 1: 100,000  <br/>  area = length × breadth  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ground area</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">length<hr size=\"1\" />100,000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">breadth<hr size=\"1\" />100,000</td></tr></table></div>  <br/>  = 288sqkm.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2005>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The railway has most probably been constructed to transport</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">passengers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farm produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forest products</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The settlements on the maps are mining settlements. Hence, the railway must have been primarily for minerals before passenger transport.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2005>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The average gradient of the rail line from the centre of Zafi to the bridge over River Saga is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:68</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:65</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:62</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:59</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gradient is semantic alternative for slope   <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">vertical distance height<hr size=\"1\" />horizontal distance(as bird flies distance)</td></tr></table></div>  <br/>  = 1/59 = 1 : 59 </div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2005>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The dominant settlement pattern in the eastern part of the map can best be described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conurbated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The settlements are dispersed as they are scattered & few away from each other.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2005>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Places that are likely to be visible from the trigonometrical station are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ligo and Pom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Figu and Ligo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kileko and Figu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pom and Kileko</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Visibility/line of sight means areas lower in height from the spot location of interest. Once a higher relief/feature pops up between source and destination then the line of sight is compromised.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2005>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the table below to answer this question</em></strong> <br/>   <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The data best describes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a cool temperate climate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a tropical monsoon climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a warm temperate climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an equatorial climate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warm temperate climate with single maximum annual rainfall.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2005>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the table below to answer this question</em></strong> <br/>   <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The annual range of temperature is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Temperature range = highest annual temperature minus lowest annual temperature  <br/>  = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C - 24<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2005>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of similar triangle is commonly used in chain survey to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overcome obstacles on survey line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estimate the angle of slope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintain a straight line between points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estimate the size of the survey area</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using the pythagoras theory & others, the principle of similar triangle can be used to overcome obstacles on survey line.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2005>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The linear scale of a map is important in that it enables the user to conveniently measure</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">areas and volumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distances and areas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume and directions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directions and distances</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Linear scales in maps are used to calculate linear dimensions which are distances & distance make up a real dimensions.</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES,"}, {"id": "objective>Geography>2005>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The reservoir was created primarily for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Industrial power generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inland fishing industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large-scale irrigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inland water transportation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the map, the reservoir was created mainly for industrial power generation.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2005>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The towns marked <strong>X</strong> and <strong>Y</strong> respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tema and Akosombo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accra and Kumasi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Takoradi and Tema</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accra and Takoradi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Takoradi and Tema are towns affiliated with the Volta Akosombo dams.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2005>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Atlas mountains of Africa are found mainly in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Egypt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Morocco</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Algeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Libya</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Atlas mountains of North Africa is found mainly in Algeria even though it cuts across other countries.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2005>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The discovery and mining of coal at the foot of the Udi Hills led to the founding of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Enugu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Okigwe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Awka</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Onitsha</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Enugu was the Administrative capital city for the region in the East Where coal was found around Udi Hills.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2005>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The major cash crop in the shaded portion is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kolanut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil palm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rubber belt of Southern Nigeria is depicted in the map. Some areas here overlap with the oil palm belt of South/Southern Nigeria.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The production of the crop is done mainly through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gathering from natural forests and plantations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plantations and large-scale irrigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed farming and small-holder cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small-holder cultivation and large-scale irrigation.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rubber plantations as well as natural forest supply the needed rubber tree gum/sap processed into rubber.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2005>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cities with populations of over one million people in Africa include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Algiers, Alexandria, Nairobi and Banjul</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cape Town, Luanda, Khartoum and Abidjan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibadan, Kampala, Bulawayo and Mombasa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cairo, Laogs, Kinshasa and Johannesburgh</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cairo, lagos, Kinshasa & Johannesburgh are all mega cities of commerce & administration in their respective countries with over 1 million inhabitants.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2005>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The geological formation with which inselbergs are commonly associated in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower cretaceous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recent deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Upper cretaceous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Basement complex</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Basement complex are old granitic rock which usually have developed smoothened sides overtime due to weathering & referred to as inselbergs.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2005>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most serious cause of desertification in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excessive high temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excessive pressure on land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extremely low rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental pollutions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Desertification is the process by which fertile land becomes desert, typically as a result of inappropriate agricultural practices, deforestation, or climate change. In Nigeria, the most serious cause of desertification is excessive pressure on land. This is due to overgrazing, deforestation for fuelwood and inappropriate agricultural practices. These activities remove the vegetation cover of the soil, making it susceptible to erosion and eventually leading to desertification.</div>", "topic": "REGIONAL GEOGRAPHY : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2005>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dominant foreign exchange earner of Senegal is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tourism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fishing is the major foreign exchange earner for senegal with territorial coastal waters in the atlantic ocean. Unfortunately River senegal is completely surrounded by the Republic of Gambia.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Recent growth in the manufacturing sector of the Nigerian economy is been mostly associated with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">growth of the petroleum industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in communication networks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in agricultural diversification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth of the iron and steel industry</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With Nigeria's non-oil economy being dominated by agriculture, the diversification of this sector has reflected in local manufacturing sector growth in recent times.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian rivers that take their sources from the Jos plateau include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chalawa, Kano and Kaduna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Katsina-Ala, Gongola and Rima</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna, Sokoto and Jama'are</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jama'are, Gongola and Kaduna</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">River Jamma' are flowing into Bauchi, Gongola into old Gongok State & Kaduna into Kaduna all have their origin from the Jos plateau.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2005>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Temperate and sub-tropical grasslands on the Africa continent are found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zimbabwe and Morocco</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malawi and South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namibia and Zambia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa and Lesotho</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South Africa & Lesotho. Both in the southern region of Africa with Lesotho. South Eastern region have temperate & Sub-Tropical grassland as a result of the shield created by the Drakensberg highlands to the coastal East.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2005>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The features shown are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rock boulders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disintegrated blocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exfoliation domes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rounded boulders</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Exfoliation domes are smoothed rock apex/peaks similar to inselbergs, only that weathering here occurs in layers like the opening of onion layers. The Sugar loaf overlooking Rio de Janeiro in Brazil is a classical example.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2005>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The features are usually associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry and wet tropics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faulted topography </div>", "<div style=\"font-family:Cambria;font-size:17px;\">folded environments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">karst regions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The repeated alternation of dry & wet season/daily dew & sunshine leads to this feature.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2005>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Equatorial trough or low-pressure belt is commonly known as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">easterlies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doldrums</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclonic front</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horse latitudes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Doldrums are equatorial trough or low-pressure belt. Cyclonic fronts are boundary lines generally are the tropics between high & low pressure air masses.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2005>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common greenhouse gas in the atmosphere is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorofluorocarbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(II)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bromide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = Carbon(IV)oxide is the most dominant green house gas in the atmosphere because of human respiration coupled with rapid deforestation.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2005>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of environmental resources is renewable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Water, Iron ore and soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water, gold and plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water, plants and soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water, soils and minerals</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Renewable resources are those that are replenished naturally and over relatively short periods of time. This includes resources like water, plants, and soils. Water is continuously cycled through the environment. Plants can regrow after harvesting and soils are formed over time from weathering of rocks and decay of organic material.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2005>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The state of equilibrium reached by the vegetation of an area when it is left undisturbed for a long time is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trophic level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">climax</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The state of equilibrium reached by the vegetation of an area when it is left undisturbed for a long time is known as the climax. In ecology, the climax community, or climatic climax community, is the state of equilibrium that a plant community will reach if undisturbed over time. It is the final stage of succession, remaining relatively unchanged until destroyed by an event such as fire or human interference.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2005>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rock minerals are said to be crystalline when the atoms forming them are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">found in sedimentary rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">found in crystalline rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arranged in a definite pattern </div>", "<div style=\"font-family:Cambria;font-size:17px;\">arranged vertically</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rock minerals are said to be crystalline when the atoms forming them are arranged in a definite pattern. This is because the term 'crystalline' refers to a solid material whose constituents, such as atoms, molecules or ions, are arranged in a highly ordered, repeating pattern extending in all three spatial dimensions.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2005>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cool ocean current may bring to the coast it washes cool and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry conditions if winds ar off shore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dry conditions if wind are on shore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wet conditions if winds are off shore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wet conditions if winds are on shore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cool ocean currents are usually dry without moisture in nature & brings these conditions on shore/to continental land when flowing from the sea to the coast.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2005>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The rock that is igneous is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(H) Igneous rock are the basement rock upon which sedimentation occurs.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2005>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Limestone can be identified within the area marked </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Limestone regions have the characteristic block-layered formation arranged over each other as found in M.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2005>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trees in the coniferous forest are noted for their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">needle leaves and softwood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">needle leaves and hardwood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">broad leaves and soft wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">broad leaves and hard wood</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coniferous forest of temperate regions characteristically have needle leaves & softwood. The softwood is what makes them good for pulp & paper industry.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2005>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference in time between two longitudes is approximately ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15 hours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 minutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 hours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 minutes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1hr° = 15°  <br/>  → 60minutes = 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>  <br/>  ∴ x minutes = 1 °  <br/>  x = 60/15 = 4minutes.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2005>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of environmental balance can be taken to mean that an alteration in one of the components of the ecosystem may result in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acceleration of the processes within the system </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disruption of the processes within the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimization of the processes within the system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilization of the processes within the system </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alternation in a component of the ecosystem disrupts the process of succession towards equilibrium in an ecosystem.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2005>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A small hill resulting from the process of peneplanation is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a hum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an arete</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monadnock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an inselberg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inselbergs are granite rocks worn down by population activities.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2005>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean currents flow in a clockwise direction in the northern hemisphere but in an anti-clockwise direction in the southern hemisphere because of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rotation of the earth from east to west </div>", "<div style=\"font-family:Cambria;font-size:17px;\">strong and more persistent winds in the southern hemisphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many active currents in the northern hemisphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotation of the earth from west to east.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ferrel's law stating the role of coriolis effect/force acting on airmasses Northward deflected eastward as the earth rotates around its axis.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2005>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tropical soil formed on wind drift material and usually featuring a laterite layer is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">latosol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithosol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regosol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">podzol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lithosols are savannah soils influenced by aeolian deposition in a vegetated surface. If this happens in a desert, then regosols are observed.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2005>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country which experiences earthquakes frequently is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cameroun </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brazil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tanzania</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Japan is located in the Pacific Ring of Fire, which is an area with a lot of seismic and volcanic activity. Therefore, Japan experiences earthquakes frequently. The Pacific Ring of Fire is a direct result of plate tectonics and the movement and collisions of lithospheric plates.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2005>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants are of primary importance to animals within an ecosystem because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can be composted and provide nutrient to soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as windbreakers and provide shades</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store nitrogen and transpire water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce oxygen and provide sinks for carbon(IV)oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Man breathes in O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> & out CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> while plants use CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> for photosynthesis & release O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> into the atmosphere for animal respiration.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2005>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most critical and variable element of weather in a tropical environment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">potential evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sunshine hours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most critical and variable element of weather in a tropical environment is rainfall. This is because rainfall in tropical environments is highly variable and unpredictable, and it has a significant impact on the ecosystem, including the types of plants and animals that can survive there. While temperature, sunshine hours, and potential evaporation are also important elements of weather, they are generally less variable in a tropical environment than rainfall.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2005>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban and rural settlements are best differentiated by their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population and function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">function and location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">function only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population = number of people & Function = kind of economic activities carried out are major determinants in differentiating urban from rural settlements.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2005>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most dense airline network in the world is found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Western Europe and Eastern Europe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North America and South America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North America and Australia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Europe and North America</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most dense airline network in the world is found in Western Europe and North America. This is due to the high level of economic development, large population, and high demand for air travel in these regions.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2005>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Harsh desert conditions are responsible for the low population density in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">west coast of South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">east coast of China</div>", "<div style=\"font-family:Cambria;font-size:17px;\">west coast of India</div>", "<div style=\"font-family:Cambria;font-size:17px;\">east coast of Latin America</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Harsh desert conditions are responsible for the low population density in the west coast of South Africa. This region is known as the Namib Desert, which is one of the oldest and driest regions in the world, making it difficult for human habitation.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2005>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The joining together of many cities results in the formation of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metropolis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">megalopolis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conurbation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mega city</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The joining together of many cities results in the formation of a conurbation. A conurbation is a region comprising a number of cities, large towns, and other urban areas that, through population growth and physical expansion, have merged to form one continuous urban and industrially developed area.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2005>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The raw  material for terylene is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">petroleum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wool</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bauxite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cotton</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Terylene is a type of polyester that is made from petroleum products. Petroleum is processed to produce ethylene glycol and terephthalic acid, which are then combined to form terylene.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important effect of migration on population is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high mortality </div>", "<div style=\"font-family:Cambria;font-size:17px;\">even distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water pollution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Migration leads to redistribution of population. It involves the movement of people from one place to another which results in the change of population distribution.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2005>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr coal field is located in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Russia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germany</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the U.S.A.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canada</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr coal field is located in Germany. It is one of the largest industrial regions in Europe and was once the largest coal-mining area in the world.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">British foreign investment are concentrated in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commonwealth countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EU countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS countries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Commonwealth countries are all part of British colonized/Independent countries with heavy British investments & economic interests.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2005>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">South-facing slopes are favourable for rural settlement locations in the cool temperate regions of the northern hemisphere because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">receive more solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are agriculturally more productive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are always well drained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer good shelter from storms</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South-facing slopes also referred to as Advet support rural settlements. In cool temperate regions, a crop cultivation is made possible & less cold experienced due to its slope & angle inclination, allowing for Solar radiation from the Equator to hit this area as against North-facing slopes which are shielded from solar radiation from the Equator.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}];
